// n8n Code node (JavaScript)
// Comparación multivariable: Bloqueo, Atención, Sucursal y Tipo de Cliente

const dataVerdad = $("Get Data").all();
const dataBase = $("Info Base").all();

const baseMap = {};
dataBase.forEach(item => {
  const tel = String(item.json.telefono || '');
  if (tel) baseMap[tel] = item.json;
});

const results = [];

for (const itemVerdad of dataVerdad) {
  const fields = itemVerdad.json.fields || {};
  const telVerdad = String(fields["Teléfono"] || '');

  // 1. Normalización de campos de Airtable (La Verdad)
  const rawBloqueo = fields["Bloqueo"] || '';
  const bloqueoAT = rawBloqueo.startsWith('Bloqueo') ? rawBloqueo : `Bloqueo ${rawBloqueo}`;

  const atencionAT = fields["Atención"] || '';
  const tipoClienteAT = fields["Tipo"] || '';

  // Extraer sucursal del array (tomamos el primer elemento)
  const sucursalAT = (Array.isArray(fields["Sucursal"]) && fields["Sucursal"].length > 0) 
    ? fields["Sucursal"][0] 
    : '';

  const registroBase = baseMap[telVerdad];

  let necesitaActualizacion = false;
  let datosBase = {
    status: "No existe",
    atencion: "No existe",
    tipo: "No existe",
    sucursal: "No existe"
  };

  if (registroBase) {
    // 2. Extraer datos de la Base de Datos
    datosBase.status = registroBase.status || '';
    datosBase.atencion = registroBase.tipo_atencion || '';
    datosBase.tipo = registroBase.tipo_cliente || '';

    // La sucursal en tu DB parece venir en sucursal_bloqueo.sucursal[0] según tu JSON
    datosBase.sucursal = (registroBase.sucursal_bloqueo && Array.isArray(registroBase.sucursal_bloqueo.sucursal))
      ? registroBase.sucursal_bloqueo.sucursal[0]
      : '';

    // 3. COMPARACIÓN CUÁDRUPLE
    if (
      bloqueoAT !== datosBase.status || 
      atencionAT !== datosBase.atencion || 
      tipoClienteAT !== datosBase.tipo || 
      sucursalAT !== datosBase.sucursal
    ) {
      necesitaActualizacion = true;
    }
  } else {
    necesitaActualizacion = true;
  }

  results.push({
    json: {
      ...itemVerdad.json,
      actualizar_db: necesitaActualizacion,
      comparativa: {
        en_airtable: {
          bloqueo: bloqueoAT,
          atencion: atencionAT,
          tipo_cliente: tipoClienteAT,
          sucursal: sucursalAT
        },
        en_base_datos: {
          bloqueo: datosBase.status,
          atencion: datosBase.atencion,
          tipo_cliente: datosBase.tipo,
          sucursal: datosBase.sucursal
        }
      }
    }
  });
}

return results;

